class InventoryError(Exception):
    """Domain errors raised by inventory service."""

class ItemNotAvailableError(InventoryError):
    pass

def activate_item(user, code):
    from apps.inventory.models import Item
    try:
        item = Item.objects.get(code=code)
    except Item.DoesNotExist:
        raise ItemNotAvailableError(f"Item {code!r} not found")
    if item.is_active:
        raise ItemNotAvailableError(f"Item {code!r} already active")
    ...
